sp(t2,t1,s2,32,32,24,24,4,4,5,5);mp(s2,ba,32,32,24);
sp(ba,t1,t2,16,16,24,48,6,6,7,7);
sp(t2,t1,s3,16,16,48,48,8,8,9,9);mp(s3,ba,16,16,48);
sp(ba,t1,t2,8,8,48,96,10,10,11,11);
sp(t2,t1,bb,8,8,96,96,12,12,13,13);
